<?php if($error):?><p class="admin-statistics-error"><?=$esc($error)?></p><?php endif;?><form class="admin-statistics-filters" method="get"><input type="hidden" name="ruta" value="admin-estadisticas"><label>Rango rápido<select name="rango"><option value="">Todo el historial</option><?php foreach(['mes'=>'Mes actual','3'=>'Últimos 3 meses','6'=>'Últimos 6 meses','anio'=>'Año actual']as$k=>$v):?><option value="<?=$k?>" <?=($_GET['rango']??'')===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Fecha inicial<input type="date" name="fecha_inicio" value="<?=$esc($_GET['fecha_inicio']??'')?>"></label><label>Fecha final<input type="date" name="fecha_fin" value="<?=$esc($_GET['fecha_fin']??'')?>"></label><label>Periodo<select name="periodo"><option value="">Todos</option><?php foreach($periodos as$p):?><option <?=$periodo===$p?'selected':''?> value="<?=$esc($p)?>"><?=PeriodoHelper::formatear($p.'-01')?></option><?php endforeach;?></select></label><button>Aplicar</button><a href="<?=BASE_URL?>/index.php?ruta=admin-estadisticas">Limpiar filtros</a></form>
<div class="admin-statistics-summary-grid"><?php foreach([['Monto recaudado','$'.number_format((float)($indicadores['recaudado']??0),2),'Solo pagos validados'],['Monto pendiente','$'.number_format((float)($indicadores['monto_pendiente']??0),2),'Adeudos pendientes'],['Pagos validados',number_format((float)($indicadores['pagos_validados']??0)),'En el rango'],['Adeudos pendientes',number_format((float)($indicadores['adeudos_pendientes']??0)),'Estado actual'],['Alumnos activos',number_format((float)($indicadores['alumnos_activos']??0)),'Padrón vigente'],['Aclaraciones pendientes',number_format((float)($indicadores['aclaraciones_pendientes']??0)),'Abiertas y en revisión']]as$x):?><article><span><?=$x[0]?></span><strong><?=$x[1]?></strong><small><?=$x[2]?></small></article><?php endforeach;?></div>
<div class="admin-statistics-grid"><?php foreach([['Ingresos recaudados por mes','statistics_income_chart','income',$ingresos],['Estado de los adeudos','statistics_debts_chart','debts',$adeudosEstado],['Métodos de pago','statistics_payment_methods_chart','methods',$metodos],['Origen de los pagos','statistics_origins_chart','origins',$origenes],['Estado de alumnos','statistics_students_chart','students',$alumnosEstado],['Estado de aclaraciones','statistics_clarifications_chart','clarifications',$aclaracionesEstado],['Estado de prórrogas','statistics_extensions_chart','extensions',$prorrogasEstado],['Pagos por estado','statistics_payments_chart','payments',$pagosEstado]]as$x):?><section class="admin-statistics-chart-card"><h2><?=$x[0]?></h2><?php if(!$x[3]):?><p class="admin-statistics-empty">No hay información disponible para el periodo seleccionado.</p><?php else:?><canvas id="<?=$x[1]?>" class="admin-statistics-chart" aria-label="<?=$x[0]?>"></canvas><div class="admin-statistics-chart-legend"><?php foreach($x[3]as$d):?><span><?=htmlspecialchars((string)($d['etiqueta']??$d['periodo']??''),ENT_QUOTES,'UTF-8')?>: <?=number_format((float)($d['cantidad']??$d['total']??0),2)?></span><?php endforeach;?></div><script type="application/json" id="statistics_<?=$x[2]?>_data"><?=$json($x[3])?></script><?php endif;?></section><?php endforeach;?></div>
<section class="admin-statistics-mounts"><h2>Montos de adeudos</h2><?php foreach(['Pendiente'=>'pendiente','Pagado'=>'pagado','Total registrado'=>'total','Recargos aplicados'=>'recargos']as$l=>$k):?><div><span><?=$l?></span><strong>$<?=number_format((float)($montosAdeudos[$k]??0),2)?></strong></div><?php endforeach;?></section>
<section class="admin-statistics-latest"><header><h2>Últimos pagos validados</h2><a href="<?=BASE_URL?>/index.php?ruta=admin-pagos&amp;estado=Validado">Consultar pagos</a></header><div><table><thead><tr><th>Fecha</th><th>Matrícula</th><th>Alumno</th><th>Periodo</th><th>Importe</th><th>Origen</th></tr></thead><tbody><?php if(!$ultimosPagos):?><tr><td colspan="6">No hay información disponible.</td></tr><?php else:foreach($ultimosPagos as$p):?><tr><td><?=$esc((new DateTimeImmutable($p['fecha_pago']))->format('d/m/Y'))?></td><td><?=$esc($p['matricula'])?></td><td><?=$esc($p['nombre'])?></td><td><?=$esc(PeriodoHelper::formatear($p['periodo']))?></td><td>$<?=number_format((float)$p['total_pagado'],2)?></td><td><?=$esc($p['origen'])?></td></tr><?php endforeach;endif;?></tbody></table></div></section><?php require __DIR__.'/../partials/footer.php';?></main></div><script src="<?=BASE_URL?>/public/js/admin.js"></script></body></html>
